import { MakeLogicType, actions, kea, path, reducers } from 'kea'
import { loaders } from 'kea-loaders'
import { urlToAction } from 'kea-router'

import api from 'lib/api'

export interface SecretMeta {
    secret_type: string
}

export interface RevealedSecret {
    secret_type: string
    value: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface revealSecretLogicValues {
    revealedSecret: RevealedSecret | null
    revealedSecretLoading: boolean
    secretMeta: SecretMeta | null
    secretMetaLoading: boolean
    token: string
    unavailable: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface revealSecretLogicActions {
    loadMeta: () => any
    loadMetaFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadMetaSuccess: (
        secretMeta: SecretMeta | null,
        payload?: any
    ) => {
        secretMeta: SecretMeta | null
        payload?: any
    }
    reveal: () => any
    revealFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    revealSuccess: (
        revealedSecret: RevealedSecret | null,
        payload?: any
    ) => {
        revealedSecret: RevealedSecret | null
        payload?: any
    }
    setToken: (token: string) => {
        token: string
    }
}

export type revealSecretLogicType = MakeLogicType<revealSecretLogicValues, revealSecretLogicActions>

export const revealSecretLogic = kea<revealSecretLogicType>([
    path(['scenes', 'reveal', 'revealSecretLogic']),
    actions({
        setToken: (token: string) => ({ token }),
    }),
    reducers({
        token: ['' as string, { setToken: (_, { token }) => token }],
        // Peek failing means the link is expired, already revealed, or not ours — all "unavailable".
        unavailable: [
            false as boolean,
            {
                setToken: () => false,
                loadMetaFailure: () => true,
                loadMetaSuccess: () => false,
                revealFailure: () => true,
            },
        ],
        // Drop any previously revealed value when the token changes, so token A's secret can never
        // render on token B's page after an in-scene navigation.
        revealedSecret: [
            null as RevealedSecret | null,
            {
                setToken: () => null,
            },
        ],
    }),
    loaders(({ values }) => ({
        // Peek: fetch only the type + availability, without consuming the secret.
        secretMeta: [
            null as SecretMeta | null,
            {
                loadMeta: async () => {
                    return await api.get(`api/one_time_secrets/${values.token}/`)
                },
            },
        ],
        // Reveal: the single call that returns the value and burns the link server-side.
        revealedSecret: [
            null as RevealedSecret | null,
            {
                reveal: async () => {
                    return await api.create(`api/one_time_secrets/${values.token}/reveal/`)
                },
            },
        ],
    })),
    urlToAction(({ actions }) => ({
        '/reveal/:token': ({ token }) => {
            if (token) {
                actions.setToken(token)
                actions.loadMeta()
            }
        },
    })),
])
